const express = require('express');
const axios = require('axios');
const morgan = require('morgan');

const app = express();
app.use(morgan(':method :url :status :res[content-length] - :response-time ms :req[api_key]'));

app.all('*', async (req, res) => {
  const backendUrl = '...';  // put your backend service url here

  // extract the api key
  const apiKey = req.query.api_key;
  if (!apiKey) {
    return res.status(401).json({ error: 'api_key is required' });
  }

  // remove api_key from query params
  delete req.query.api_key;

  try {
    const resp = await axios({
      method: req.method,
      url: backendUrl + req.path,
      headers: {
        ...req.headers,
        'api_key': apiKey
      },
      params: req.query,
      data: req.body
    });

    res.status(resp.status).json(resp.data);
  } catch (err) {
    if (err.response && err.response.status) {
      res.status(err.response.status).json(err.response.data);
    } else {
      res.status(500).json({ error: err.toString() });
    }
  }
});

const port = process.env.PORT || 3000;
app.listen(port, () => console.log(`API Gateway is listening on port ${port}`));